import{_ as s,o as n,c as e,a5 as t}from"./chunks/framework.BDsA2zRs.js";const u=JSON.parse('{"title":"IMPL-004 — 소스 디렉토리 구조 재편 (src-layout)","description":"","frontmatter":{},"headers":[],"relativePath":"decision-log/impl-src-layout.md","filePath":"decision-log/impl-src-layout.md"}'),o={name:"decision-log/impl-src-layout.md"};function d(p,a,c,i,l,r){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="impl-004-—-소스-디렉토리-구조-재편-src-layout" tabindex="-1">IMPL-004 — 소스 디렉토리 구조 재편 (src-layout) <a class="header-anchor" href="#impl-004-—-소스-디렉토리-구조-재편-src-layout" aria-label="Permalink to &quot;IMPL-004 — 소스 디렉토리 구조 재편 (src-layout)&quot;">​</a></h1><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>날짜</td><td>2026-03-20</td></tr><tr><td>브랜치</td><td><code>refactor/src-layout</code></td></tr><tr><td>상위 결정</td><td><a href="/rest-domain-state-manager/decision-log/ard-0001.html">ARD-0001</a></td></tr><tr><td>상태</td><td>완료</td></tr></tbody></table><h2 id="_1-문제-정의" tabindex="-1">1. 문제 정의 <a class="header-anchor" href="#_1-문제-정의" aria-label="Permalink to &quot;1. 문제 정의&quot;">​</a></h2><h3 id="_1-1-파편화된-디렉토리-구조" tabindex="-1">1.1 파편화된 디렉토리 구조 <a class="header-anchor" href="#_1-1-파편화된-디렉토리-구조" aria-label="Permalink to &quot;1.1 파편화된 디렉토리 구조&quot;">​</a></h3><p>ARD-0000이 진단한 치명적 설계 결함 중 하나는 핵심 도메인 모델 파일들이 <code>src/</code> 밖에 위치한다는 것이었다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 개선 전 — 파편화 상태</span></span>
<span class="line"><span>root/</span></span>
<span class="line"><span>├── rest-domain-state-manager.js   ← 진입점 파일명도 컨벤션에 어긋남</span></span>
<span class="line"><span>├── model/                         ← src/ 밖 파편 1</span></span>
<span class="line"><span>│   ├── DomainState.js</span></span>
<span class="line"><span>│   ├── DomainVO.js</span></span>
<span class="line"><span>│   └── DomainPipeline.js</span></span>
<span class="line"><span>├── plugin/                        ← src/ 밖 파편 2</span></span>
<span class="line"><span>│   ├── domain-renderer/</span></span>
<span class="line"><span>│   └── form-binding/</span></span>
<span class="line"><span>└── src/</span></span>
<span class="line"><span>    ├── core/</span></span>
<span class="line"><span>    ├── handler/                   ← 역할을 나타내지 않는 이름</span></span>
<span class="line"><span>    ├── common/</span></span>
<span class="line"><span>    ├── constants/</span></span>
<span class="line"><span>    └── debug/</span></span></code></pre></div><p>이 구조의 문제점은 세 가지였다.</p><p><strong>번들러 Entry Point 추적 복잡성:</strong> <code>tsconfig.json</code> 의 <code>include</code> 가 <code>&quot;src/**/*&quot;</code>, <code>&quot;model/**/*&quot;</code>, <code>&quot;plugin/**/*&quot;</code> 으로 세 경로를 별도 지정해야 했다. Vite의 번들링 시 모든 진입점이 서로 다른 컨텍스트에서 시작되어 Tree-shaking 분석이 복잡해진다.</p><p><strong>Tree-shaking 효율 저하:</strong> NPM 패키지의 Tree-shaking이 효과적으로 작동하려면 모든 모듈이 하나의 루트 아래 응집되어 있어야 한다. 파편화된 구조에서 번들러는 모듈 간 의존 관계를 정확히 추적하기 어렵다.</p><p><strong><code>src/handler/</code> 이름:</strong> <code>ApiHandler</code> 가 HTTP 전송 레이어임을 나타내지 않는다. 동일한 역할 범주의 파일이 추가될 때 어떤 디렉토리에 속해야 하는지 기준이 불명확하다.</p><h2 id="_2-설계-결정" tabindex="-1">2. 설계 결정 <a class="header-anchor" href="#_2-설계-결정" aria-label="Permalink to &quot;2. 설계 결정&quot;">​</a></h2><h3 id="_2-1-목표-디렉토리-구조" tabindex="-1">2.1 목표 디렉토리 구조 <a class="header-anchor" href="#_2-1-목표-디렉토리-구조" aria-label="Permalink to &quot;2.1 목표 디렉토리 구조&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 개선 후 — src/ 중심 응집</span></span>
<span class="line"><span>root/</span></span>
<span class="line"><span>├── index.js                       ← 진입점 (컨벤션 준수)</span></span>
<span class="line"><span>└── src/</span></span>
<span class="line"><span>    ├── domain/                    ← (was: model/)</span></span>
<span class="line"><span>    │   ├── DomainState.js</span></span>
<span class="line"><span>    │   ├── DomainVO.js</span></span>
<span class="line"><span>    │   └── DomainPipeline.js</span></span>
<span class="line"><span>    ├── network/                   ← (was: src/handler/)</span></span>
<span class="line"><span>    │   └── api-handler.js</span></span>
<span class="line"><span>    ├── plugins/                   ← (was: plugin/)</span></span>
<span class="line"><span>    │   ├── domain-renderer/</span></span>
<span class="line"><span>    │   └── form-binder/           ← (was: form-binding/)</span></span>
<span class="line"><span>    ├── core/</span></span>
<span class="line"><span>    ├── common/</span></span>
<span class="line"><span>    ├── constants/</span></span>
<span class="line"><span>    └── debug/</span></span></code></pre></div><p>이 구조에서 <code>tsconfig.json include</code> 는 <code>[&quot;src/**/*&quot;, &quot;index.js&quot;]</code> 하나의 패턴으로 통합된다.</p><h3 id="_2-2-이름-변경-결정-근거" tabindex="-1">2.2 이름 변경 결정 근거 <a class="header-anchor" href="#_2-2-이름-변경-결정-근거" aria-label="Permalink to &quot;2.2 이름 변경 결정 근거&quot;">​</a></h3><table tabindex="0"><thead><tr><th>이전</th><th>이후</th><th>이유</th></tr></thead><tbody><tr><td><code>model/</code></td><td><code>src/domain/</code></td><td>DDD(Domain-Driven Design)의 용어 체계. 도메인 모델임을 명시</td></tr><tr><td><code>plugin/</code></td><td><code>src/plugins/</code></td><td><code>src/</code> 통합 + 복수형으로 일관성 유지</td></tr><tr><td><code>src/handler/</code></td><td><code>src/network/</code></td><td>HTTP 전송 레이어(Transport Layer)임을 명시</td></tr><tr><td><code>plugin/form-binding/</code></td><td><code>src/plugins/form-binder/</code></td><td>파일명 <code>FormBinder.js</code> 와 일치시킴</td></tr><tr><td><code>rest-domain-state-manager.js</code></td><td><code>index.js</code></td><td>NPM 패키지 진입점 컨벤션(<code>index.js</code>) 준수</td></tr></tbody></table><h3 id="_2-3-로직-변경-없는-순수-구조-작업" tabindex="-1">2.3 로직 변경 없는 순수 구조 작업 <a class="header-anchor" href="#_2-3-로직-변경-없는-순수-구조-작업" aria-label="Permalink to &quot;2.3 로직 변경 없는 순수 구조 작업&quot;">​</a></h3><p>이 리팩토링은 파일 이동과 import 경로 갱신만 포함한다. 어떤 비즈니스 로직도 변경하지 않았다. 이것이 <code>feature/</code> 가 아닌 <code>refactor/</code> 브랜치를 사용한 근거다.</p><h2 id="_3-변경-파일-및-커밋-시퀀스" tabindex="-1">3. 변경 파일 및 커밋 시퀀스 <a class="header-anchor" href="#_3-변경-파일-및-커밋-시퀀스" aria-label="Permalink to &quot;3. 변경 파일 및 커밋 시퀀스&quot;">​</a></h2><p>파일 이동(커밋 1)과 import 경로 갱신(커밋 2)을 분리했다. 커밋 1 단독으로는 빌드가 실패하는 상태이나, 두 커밋을 분리하면 이동 diff와 경로 갱신 diff를 명확히 구분하여 리뷰할 수 있다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 커밋 1 — 파일 이동만 (import 경로 수정 없음)</span></span>
<span class="line"><span>refactor(structure): move model/, plugin/, handler/ under src/ hierarchy</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 커밋 2 — import 경로 전체 갱신</span></span>
<span class="line"><span>refactor(structure, config): update all import paths, vite, tsconfig,</span></span>
<span class="line"><span>  and JSDoc @module tags for new directory layout</span></span></code></pre></div><p><strong>TypeDoc JSDoc 링크 수정 (커밋 2 포함):</strong> 구조 이동 후 TypeDoc 빌드에서 <code>{@link module:handler/api-handler}</code> 형태의 <code>module:</code> 네임스페이스 구문이 resolve되지 않는 에러가 발생했다. TypeDoc은 <code>{@link module:X}</code> 구문을 지원하지 않으며 심볼명을 직접 참조해야 한다. 11개 파일의 JSDoc <code>@see</code> 링크를 <code>{@link SymbolName}</code> 형태로 전면 교체했다.</p><h2 id="_4-결과-및-검증" tabindex="-1">4. 결과 및 검증 <a class="header-anchor" href="#_4-결과-및-검증" aria-label="Permalink to &quot;4. 결과 및 검증&quot;">​</a></h2><p><strong>빌드 검증:</strong> 커밋 2 이후 <code>npm run build</code> 통과. <code>dist/index.js</code>, <code>dist/index.cjs</code>, <code>dist/index.d.ts</code> 정상 생성.</p><p><strong>TypeDoc 검증:</strong> <code>npm run docs:api</code> 통과. <code>docs/api/</code> 하위 레퍼런스 파일들 정상 생성.</p><p><strong>테스트 검증:</strong> <code>npm test</code> 79/79 케이스 통과. 구조 변경이 기존 동작에 영향을 주지 않음 확인.</p>`,26)])])}const m=s(o,[["render",d]]);export{u as __pageData,m as default};
